def render(pieces, style):
    """
    Render the given version pieces into the requested style.
    """
    if style == "simple":
        return ".".join(map(str, pieces))
    elif style == "detailed":
        return "-".join(map(str, pieces))
    else:
        raise ValueError("Unsupported style")

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Together with :func:``update_last_applied_manifest_dict_from_resp``, this
function is called recursively to update a partial ``last_applied_manifest``
from a partial Kubernetes response

Args:
    last_applied_manifest (list): partial ``last_applied_manifest`` being
        updated
    observer_schema (list): partial ``observer_schema``
    response (list): partial response from the Kubernetes API.

This function go through all observed fields, and initialized their value in
last_applied_manifest if they are not yet present
    """

    for item in response:
        if isinstance(item, dict):
            for key, value in item.items():
                if key not in last_applied_manifest:
                    last_applied_manifest[key] = value
                elif isinstance(last_applied_manifest[key], dict) and isinstance(value, dict):
                    update_last_applied_manifest_list_from_resp(last_applied_manifest[key], observer_schema, [value])
                elif isinstance(last_applied_manifest[key], list) and isinstance(value, list):
                    update_last_applied_manifest_list_from_resp(last_applied_manifest[key], observer_schema, value)
        elif isinstance(item, list):
            update_last_applied_manifest_list_from_resp(last_applied_manifest, observer_schema, item)

    return last_applied_manifest

def popitem(self):
    """
    Remove and return the `(key, value)` pair least frequently used.
    """
    if not self.cache:
        raise KeyError("popitem(): dictionary is empty")

    least_frequent_key = min(self.cache, key=lambda k: self.cache[k][1])
    value = self.cache.pop(least_frequent_key)[0]
    return (least_frequent_key, value)

