def verifyClass(iface, candidate, tentative=False):
    """
    Verify that the *candidate* might correctly provide *iface*.
    """
    if not isinstance(iface, type) or not isinstance(candidate, type):
        return False

    if not issubclass(candidate, iface):
        return False

    if tentative:
        return True

    for method in dir(iface):
        if method.startswith('__') and method.endswith('__'):
            continue

        if not hasattr(candidate, method):
            return False

        iface_method = getattr(iface, method)
        candidate_method = getattr(candidate, method)

        if not callable(iface_method) or not callable(candidate_method):
            continue

        if iface_method.__code__ != candidate_method.__code__:
            return False

    return True

