def cached(cache, key=hashkey, lock=None):
    """
    Decorator to wrap a function with a memoizing callable that saves
    results in a cache.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = key(*args, **kwargs)
            if lock:
                with lock:
                    return cache.get(cache_key) or cache.setdefault(cache_key, func(*args, **kwargs))
            else:
                return cache.get(cache_key) or cache.setdefault(cache_key, func(*args, **kwargs))
        return wrapper
    return decorator

def run_command(commands, args, cwd=None, verbose=False, hide_stderr=False, env=None):
    """
    Call the given command(s).
    """
    import subprocess

    if isinstance(commands, str):
        commands = [commands]

    if not isinstance(args, list):
        raise ValueError("args should be a list")

    for command in commands:
        try:
            if verbose:
                print(f"Running command: {command} {' '.join(args)}")

            result = subprocess.run(
                [command] + args,
                cwd=cwd,
                env=env,
                capture_output=not verbose,
                text=True,
                check=True
            )

            if verbose:
                print(result.stdout)

        except subprocess.CalledProcessError as e:
            if not hide_stderr:
                print(e.stderr)
            raise

def tzname_in_python2(namefunc):
    """
    Change unicode output into bytestrings in Python 2

    tzname() API changed in Python 3. It used to return bytes, but was changed
    to unicode strings
    """
    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)
        if isinstance(result, tuple):
            return tuple(s.encode('utf-8') if isinstance(s, unicode) else s for s in result)
        return result
    return wrapper

