def next_version(version):
    """
    Next version identifier following existing pattern.

    Must deal with both zero-prefixed and non-zero prefixed versions.
    """
    parts = version.split('.')
    for i in range(len(parts) - 1, -1, -1):
        if parts[i] == '9':
            parts[i] = '0'
        else:
            parts[i] = str(int(parts[i]) + 1)
            break
    else:
        parts.insert(0, '1')
    return '.'.join(parts)

