def format(
    self,
    sql: AnyStr,
    params: Union[Dict[Union[str, int], Any], Sequence[Any]],
) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:
    if isinstance(params, dict):
        # Named parameter style
        formatted_sql = sql
        out_params = {}
        for i, (key, value) in enumerate(params.items(), start=1):
            placeholder = f":{key}"
            formatted_sql = formatted_sql.replace(placeholder, f"%({key})s")
            out_params[key] = value
    else:
        # Ordinal parameter style
        formatted_sql = sql
        out_params = list(params)
        for i, value in enumerate(params, start=1):
            formatted_sql = formatted_sql.replace("?", f"%({i})s")

    return formatted_sql, out_params

