def parse_frequency(frequency):
    """
    Given a frequency string with a number and a unit of time, return a corresponding
    datetime.timedelta instance or None if the frequency is None or "always".

    For instance, given "3 weeks", return datetime.timedelta(weeks=3)

    Raise ValueError if the given frequency cannot be parsed.
    """
    import re
    from datetime import timedelta

    if frequency is None or frequency.lower() == "always":
        return None

    match = re.match(r"(\d+)\s*(\w+)", frequency)
    if not match:
        raise ValueError(f"Cannot parse frequency: {frequency}")

    number, unit = match.groups()
    number = int(number)
    unit = unit.lower()

    if "week" in unit:
        return timedelta(weeks=number)
    elif "day" in unit:
        return timedelta(days=number)
    elif "hour" in unit:
        return timedelta(hours=number)
    elif "minute" in unit:
        return timedelta(minutes=number)
    elif "second" in unit:
        return timedelta(seconds=number)
    else:
        raise ValueError(f"Unknown time unit in frequency: {frequency}")

def formatmany(
    self,
    sql: AnyStr,
    many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    formatted_sql = sql
    converted_params = []

    for params in many_params:
        if isinstance(params, dict):
            converted_params.append(params)
            for key, value in params.items():
                placeholder = f":{key}"
                formatted_sql = formatted_sql.replace(placeholder, f"%({key})s")
        elif isinstance(params, Sequence):
            converted_params.append(params)
            for i, value in enumerate(params):
                placeholder = f"%{i+1}"
                formatted_sql = formatted_sql.replace(placeholder, "%s")
        else:
            raise ValueError("Invalid params type. Must be dict or Sequence.")

    return formatted_sql, converted_params

