def deep_merge_nodes(nodes):
    from collections import defaultdict
    from ruamel.yaml.nodes import ScalarNode, MappingNode

    def merge_mapping_nodes(node1, node2):
        merged_value = []
        keys1 = {child[0].value: child for child in node1.value}
        keys2 = {child[0].value: child for child in node2.value}

        all_keys = set(keys1.keys()).union(set(keys2.keys()))

        for key in all_keys:
            if key in keys1 and key in keys2:
                if isinstance(keys1[key][1], MappingNode) and isinstance(keys2[key][1], MappingNode):
                    merged_value.append((keys1[key][0], merge_mapping_nodes(keys1[key][1], keys2[key][1])))
                else:
                    merged_value.append((keys2[key][0], keys2[key][1]))
            elif key in keys1:
                merged_value.append(keys1[key])
            else:
                merged_value.append(keys2[key])

        return MappingNode(tag=node1.tag, value=merged_value)

    merged_nodes = defaultdict(list)

    for key, value in nodes:
        merged_nodes[key.value].append(value)

    result = []
    for key, values in merged_nodes.items():
        if len(values) > 1:
            merged_value = merge_mapping_nodes(values[0], values[-1])
        else:
            merged_value = values[0]
        result.append((ScalarNode(tag=values[0].tag, value=key), merged_value))

