    all_digests = set()
    for manifest in manifest_files:
        with open(manifest, 'r') as f:
            data = json.load(f)
            if 'digests' in data:
                all_digests.update(data['digests'])

    missing_digests = all_digests - set(digests_used)
    if missing_digests:
        raise ValueError(f"Missing digests: {missing_digests}")

    unused_digests = set(digests_used) - all_digests
    if unused_digests:
        raise ValueError(f"Unused digests: {unused_digests}")

def _resolve_string(matcher):
    """
    Get the value from environment given a matcher containing a name and an optional default value.
    If the variable is not defined in environment and no default value is provided, an Error is raised.
    """
    name = matcher.get('name')
    default = matcher.get('default')

    if name not in os.environ:
        if default is not None:
            return default
        else:
            raise KeyError(f"Environment variable '{name}' is not set and no default value is provided.")

    return os.environ[name]

