    internal consistency.
    """
    if not isinstance(prior, InventoryValidator):
        raise TypeError("prior must be an InventoryValidator object")

    if self.timestamp <= prior.timestamp:
        raise ValueError("prior must be an earlier version of the current inventory")

    if len(self.items) != len(prior.items):
        raise ValueError("Inventories must have the same number of items")

    for item in self.items:
