def deep_merge_nodes(nodes):
    from collections import defaultdict
    from ruamel.yaml.nodes import ScalarNode, MappingNode

    def merge_mapping_nodes(node1, node2):
        merged_value = []
        node1_dict = {key.value: value for key, value in node1.value}
        node2_dict = {key.value: value for key, value in node2.value}

        all_keys = set(node1_dict.keys()).union(set(node2_dict.keys()))

        for key in all_keys:
            if key in node1_dict and key in node2_dict:
                if isinstance(node1_dict[key], MappingNode) and isinstance(node2_dict[key], MappingNode):
                    merged_value.append((
                        ScalarNode(tag='tag:yaml.org,2002:str', value=key),
                        merge_mapping_nodes(node1_dict[key], node2_dict[key])
                    ))
                else:
                    merged_value.append((
                        ScalarNode(tag='tag:yaml.org,2002:str', value=key),
                        node2_dict[key]
                    ))
            elif key in node1_dict:
                merged_value.append((
                    ScalarNode(tag='tag:yaml.org,2002:str', value=key),
                    node1_dict[key]
                ))
            else:
                merged_value.append((
                    ScalarNode(tag='tag:yaml.org,2002:str', value=key),
                    node2_dict[key]
                ))

        return MappingNode(tag='tag:yaml.org,2002:map', value=merged_value)

    merged_nodes = defaultdict(lambda: None)

    for key, value in nodes:
        if isinstance(key, ScalarNode):
            if merged_nodes[key.value] is None:
                merged_nodes[key.value] = value
            else:
                if isinstance(merged_nodes[key.value], MappingNode) and isinstance(value, MappingNode):
                    merged_nodes[key.value] = merge_mapping_nodes(merged_nodes[key.value], value)
                else:
                    merged_nodes[key.value] = value

    return [(ScalarNode(tag='tag:yaml.org,2002:str', value=key), value) for key, value in merged_nodes.items()]

