    return result

def minimalBases(classes):
    """
    Reduce a list of base classes to its ordered minimum equivalent
    """
    def get_bases(cls):
        return set(cls.__bases__)

    def is_subset(sub, sup):
        return sub.issubset(sup)

    minimal = []
    for cls in classes:
        bases = get_bases(cls)
        if not any(is_subset(bases, get_bases(m)) for m in minimal):
            minimal = [m for m in minimal if not is_subset(get_bases(m), bases)]
            minimal.append(cls)
    return minimal

def run_command(commands, args, cwd=None, verbose=False, hide_stderr=False, env=None):
    """
    Call the given command(s).
    """
    import subprocess

    if isinstance(commands, str):
        commands = [commands]

    for command in commands:
        if verbose:
            print(f"Running command: {command} {' '.join(args)}")

        try:
            result = subprocess.run(
                [command] + args,
                cwd=cwd,
                env=env,
                stdout=subprocess.PIPE if hide_stderr else None,
                stderr=subprocess.PIPE if hide_stderr else None,
                text=True
            )

            if result.returncode != 0:
                if not hide_stderr:
                    print(result.stderr)
                raise subprocess.CalledProcessError(result.returncode, command)

            if verbose:
                print(result.stdout)

        except subprocess.CalledProcessError as e:
            print(f"Command '{command}' failed with return code {e.returncode}")
            raise

    return result.stdout

