def _dump_string(obj, dumper=None):
    """
    Dump to a py2-unicode or py3-string
    """
    if isinstance(obj, bytes):
        return obj.decode('utf-8')
    elif isinstance(obj, str):
        return obj
    elif isinstance(obj, (int, float, bool, type(None))):
        return str(obj)
    elif isinstance(obj, (list, tuple)):
        return [self._dump_string(item, dumper) for item in obj]
    elif isinstance(obj, dict):
        return {self._dump_string(key, dumper): self._dump_string(value, dumper) for key, value in obj.items()}
    else:
        if dumper is not None:
            return dumper(obj)
        raise TypeError(f"Object of type {type(obj)} is not JSON serializable")

def _normalizeargs(sequence, output=None):
    """
    Normalize declaration arguments

    Normalization arguments might contain Declarions, tuples, or single
    interfaces.

    Anything but individial interfaces or implements specs will be expanded.
    """
    if output is None:
        output = []

    for item in sequence:
        if isinstance(item, (list, tuple)):
            output.extend(self._normalizeargs(item))
        elif isinstance(item, str) and ':' in item:
            interface, implements = item.split(':', 1)
            output.append((interface.strip(), implements.strip()))
        else:
            output.append(item)

    return output

