    https://diaspora.github.io/diaspora_federation/discovery/webfinger.html
    """
    try:
        # Try parsing as JSON
        data = json.loads(document)
        return {
            "subject": data.get("subject"),
            "links": data.get("links", [])
        }
    except json.JSONDecodeError:
        # If JSON parsing fails, try parsing as XRD
        root = etree.fromstring(document)
        subject = root.find(".//{http://docs.oasis-open.org/ns/xrd/xrd-1.0}subject")
        links = root.findall(".//{http://docs.oasis-open.org/ns/xrd/xrd-1.0}Link")

        return {
            "subject": subject.text if subject is not None else None,
            "links": [
                {
                    "rel": link.get("rel"),
