def from_ticks(cls, ticks, tz=None):
    if not (0 <= ticks < 86400000000000):
        raise ValueError("ticks is out of bounds (0 <= ticks < 86400000000000)")

    seconds = ticks // 10000000
    microseconds = (ticks % 10000000) // 1000

    time = datetime.time(
        hour=seconds // 3600,
        minute=(seconds % 3600) // 60,
        second=seconds % 60,
        microsecond=microseconds,
        tzinfo=tz
    )

    return cls(time)

def list_of_file_names(settings_dirs, spec_option):
    """
    Create a new IniType complex type
    """
    file_names = []
    for directory in settings_dirs:
        for root, dirs, files in os.walk(directory):
            for file in files:
                if spec_option is None or file.endswith(spec_option):
                    file_names.append(os.path.join(root, file))
    return file_names

def values(self, *keys):
    if not keys:
        return list(self._data.values())
    result = []
    for key in keys:
        if isinstance(key, int):
            try:
                result.append(list(self._data.values())[key])
            except IndexError:
                pass
        elif key in self._data:
            result.append(self._data[key])
    return result

def fix_namespace_prefix_w(content):
