def protocol_handlers(cls, protocol_version=None):
    handlers = {
        (1, 7): HandlerV1_7,
        (1, 8): HandlerV1_8,
        (2, 0): HandlerV2_0,
        (3, 0): HandlerV3_0,
        (3, 1): HandlerV3_1,
        (3, 2): HandlerV3_2,
        (3, 3): HandlerV3_3,
        (3, 4): HandlerV3_4,
        (3, 5): HandlerV3_5,
        (3, 6): HandlerV3_6,
        (4, 0): HandlerV4_0,
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("Protocol version must be passed as a tuple")
        return {protocol_version: handlers.get(protocol_version)}

    return handlers

def match_pubdate(node, pubdate_xpaths):
    """
    Returns the first match in the pubdate_xpaths list
    """
    for xpath in pubdate_xpaths:
        match = node.xpath(xpath)
        if match:
            return match[0]
    return None

def data(self, *keys):
    result = {}
    if not keys:
        keys = self.keys()
    for key in keys:
        if isinstance(key, int):
            if key < 0 or key >= len(self.keys()):
                raise IndexError("Index out of bounds")
            actual_key = self.keys()[key]
        else:
            actual_key = key
        result[actual_key] = self.get(actual_key)
    return result

def parser_flags(parser):
    """
    Given an argparse.ArgumentParser instance, return its argument flags in a space-separated
string.
    """
    flags = []
    for action in parser._actions:
        if isinstance(action, argparse._StoreAction):
            flags.append(f"--{action.dest}")
        elif isinstance(action, argparse._StoreTrueAction):
            flags.append(f"--{action.dest}")
        elif isinstance(action, argparse._StoreFalseAction):
            flags.append(f"--no-{action.dest}")
        elif isinstance(action, argparse._AppendAction):
            flags.append(f"--{action.dest}")
        elif isinstance(action, argparse._AppendConstAction):
            flags.append(f"--{action.dest}")
        elif isinstance(action, argparse._CountAction):
            flags.append(f"--{action.dest}")
        elif isinstance(action, argparse._HelpAction):
            flags.append("-h")
        elif isinstance(action, argparse._VersionAction):
            flags.append("--version")
    return " ".join(flags)

def _update_context(self, context):
    """
    Update *context* with the properties of this graph.

    *context.error* is appended with indices of errors.
    Example subcontext for a graph with fields "E,t,error_E_low":
    {"error": {"x_low": {"index": 2}}}.
    Note that error names are called "x", "y" and "z"
    (this corresponds to first three coordinates,
    if they are present), which allows to simplify plotting.
    Existing values are not removed
    from *context.value* and its subcontexts.

    Called on "destruction" of the graph (for example,
    in :class:`.ToCSV`). By destruction we mean conversion
    to another structure (like text) in the flow.
    The graph object is not really destroyed in this process.
    """
    if not hasattr(context, 'error'):
        context.error = {}

    for i, field in enumerate(self.fields):
        if field.startswith('error_'):
            error_name = ['x', 'y', 'z'][i % 3]
            error_type = field.split('_')[1]
            if error_name not in context.error:
                context.error[error_name] = {}
            context.error[error_name][error_type] = {'index': i}

    if not hasattr(context, 'value'):
        context.value = {}

    for field in self.fields:
        if field not in context.value:
            context.value[field] = getattr(self, field, None)

def pop_u16(self):
    if len(self.data) < 2:
        raise ValueError("Not enough data to pop 2 bytes")
    value = int.from_bytes(self.data[-2:], byteorder='big')
    self.data = self.data[:-2]
    return value

def _extract_number_and_supplment_from_issue_element(issue):
    """
    Extract the possible values of number and suppl from the contents of issue.
    """
    number = None
    suppl = None

    if isinstance(issue, dict):
        if 'number' in issue:
            number = issue['number']
        if 'suppl' in issue:
            suppl = issue['suppl']
    elif isinstance(issue, str):
        import re
        number_match = re.search(r'number:\s*(\d+)', issue)
        suppl_match = re.search(r'suppl:\s*(\w+)', issue)

        if number_match:
            number = int(number_match.group(1))
        if suppl_match:
            suppl = suppl_match.group(1)

    return number, suppl

def _get_seq_with_type(seq, bufsize=None):
    """
    Return a (sequence, type) pair.
    Sequence is derived from *seq*
    (or is *seq*, if that is of a sequence type).
    """
    if isinstance(seq, (str, bytes, bytearray)):
        return seq, type(seq)
    elif hasattr(seq, '__iter__'):
        if bufsize is None:
            return list(seq), list
        else:
            return list(seq, bufsize), list
    else:
        raise TypeError(f"Object of type {type(seq).__name__} is not a sequence")

