def discard(self, n=-1, qid=-1, dehyd_hooks=None, hydrate_hooks=None, **handlers):
    message = {
        'type': 'DISCARD',
        'n': n,
        'qid': qid
    }

    if dehyd_hooks:
        message['dehydration_hooks'] = dehyd_hooks

    if hydrate_hooks:
        message['hydration_hooks'] = hydrate_hooks

    self._output_queue.append(message)

    return self._create_response(**handlers)

def pretty(self, indent=0, debug=False):
    """
    Return a pretty formatted representation of self.
    """
    result = []
    for key, value in self.__dict__.items():
        if isinstance(value, (dict, list)):
            result.append(f"{' ' * indent}{key}:")
            if isinstance(value, dict):
                for k, v in value.items():
                    result.append(f"{' ' * (indent + 2)}{k}: {v}")
            else:
                for item in value:
                    result.append(f"{' ' * (indent + 2)}- {item}")
        else:
            result.append(f"{' ' * indent}{key}: {value}")

    if debug:
        result.append(f"Debug info: {self.__class__.__name__} instance with {len(self.__dict__)} attributes")

    return "\n".join(result)

def scale(self, other=None, recompute=False):
    if other is None:
        if not self._scale_computed or recompute:
            if self._scale == 0:
                raise LenaValueError("Cannot rescale a histogram with scale equal to zero.")
            self._scale = self._compute_scale()
            self._scale_computed = True
        return self._scale
    else:
        if self._scale == 0:
            raise LenaValueError("Cannot rescale a histogram with scale equal to zero.")
        self._scale = other
        self._scale_computed = True

def is_fill_request_seq(seq):
    """
    Test whether *seq* can be converted to a FillRequestSeq.

    True only if it is a FillRequest element
    or contains at least one such,
    and it is not a Source sequence.
    """
    if isinstance(seq, FillRequest):
        return True
    elif isinstance(seq, Sequence):
        return any(isinstance(item, FillRequest) for item in seq)
    elif isinstance(seq, Source):
        return False
    else:
        return False

def validate_from_content(cls, spec_content=None):
    """
    validates that spec (YAML) content has all required fields

:param spec_content: content of spec file
:raise IRValidatorException: when mandatory data
is missing in spec file
:return: Dictionary with data loaded from a spec (YAML) file
    """
    if spec_content is None:
        raise IRValidatorException("Spec content is required")

    try:
        spec_data = yaml.safe_load(spec_content)
    except yaml.YAMLError as e:
        raise IRValidatorException(f"Invalid YAML format: {str(e)}")

    required_fields = ['name', 'version', 'description']
    for field in required_fields:
        if field not in spec_data:
            raise IRValidatorException(f"Missing required field: {field}")

    return spec_data

def scale(self, other=None):
    if other is None:
        return self._scale
    if not isinstance(other, (int, float)):
        raise TypeError("The 'other' parameter must be a numeric value.")
    if self._scale == 0:
        raise ValueError("Cannot rescale a graph with zero scale.")
    self._scale = other
    self._rescale_coordinates()
    return self._scale

def absorb(self, args):
    result = []
    for expr in args:
        if isinstance(expr, (And, Or)):
            left, right = expr.args
            if isinstance(left, Not):
                if isinstance(right, Or):
                    result.append(And(left.args[0], right.args[1]))
                elif isinstance(right, And):
                    result.append(Or(left.args[0], right.args[1]))
            elif isinstance(right, Not):
                if isinstance(left, Or):
                    result.append(left)
                elif isinstance(left, And):
                    result.append(left)
            else:
                result.append(expr)
        else:
            result.append(expr)
    return result

def is_fill_request_el(obj):
    """
    Object contains executable methods 'fill' and 'request'.
    """
    return hasattr(obj, 'fill') and hasattr(obj, 'request') and callable(getattr(obj, 'fill')) and callable(getattr(obj, 'request'))

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    if number == 0:
        return alphabet[0] if padding is None or padding == 1 else alphabet[0] * padding

    base = len(alphabet)
    result = []

    while number > 0:
        number, remainder = divmod(number, base)
        result.append(alphabet[remainder])

    if padding is not None:
        while len(result) < padding:
            result.append(alphabet[0])

    return ''.join(reversed(result))

def validate_from_file(cls, yaml_file=None):
    """
    Loads & validates that a YAML file has all required fields

    :param yaml_file: Path to YAML file
    :raise IRValidatorException: when mandatory data is missing in file
    :return: Dictionary with data loaded from a YAML file
    """
    if yaml_file is None:
        raise ValueError("YAML file path is required")

    try:
        with open(yaml_file, 'r') as file:
            data = yaml.safe_load(file)
    except FileNotFoundError:
        raise IRValidatorException(f"YAML file not found: {yaml_file}")
    except yaml.YAMLError as e:
        raise IRValidatorException(f"Error parsing YAML file: {e}")

    required_fields = ['name', 'version', 'dependencies']
    for field in required_fields:
        if field not in data:
            raise IRValidatorException(f"Missing required field: {field}")

    return data

def is_run_el(obj):
    """
