def _replace_register(flow_params, register_number, register_value):
    """
    Replace value from flows to given register number

    'register_value' key in dictionary will be replaced by register number
    given by 'register_number'

    :param flow_params: Dictionary containing defined flows
    :param register_number: The number of register where value will be stored
    :param register_value: Key to be replaced by register number
    """
    for flow in flow_params.values():
        if isinstance(flow, dict):
            for key, value in flow.items():
                if value == register_value:
                    flow[key] = register_number
        elif isinstance(flow, list):
            for i, item in enumerate(flow):
                if item == register_value:
                    flow[i] = register_number
    return flow_params

def hist_to_graph(hist, make_value=None, get_coordinate="left",
                  field_names=("x", "y"), scale=None):
    graph = []
    for bin in hist.bins:
        if make_value:
            value = make_value(bin)
        else:
            value = bin.content

        if get_coordinate == "left":
            coordinate = bin.left
        elif get_coordinate == "right":
            coordinate = bin.right
        elif get_coordinate == "middle":
            coordinate = bin.middle
        else:
            raise ValueError("Invalid get_coordinate value")

        if len(field_names) == 1:
            graph.append({field_names[0]: coordinate, field_names[1]: value})
        elif len(field_names) == 2:
            graph.append({field_names[0]: coordinate, field_names[1]: value[0], field_names[2]: value[1]})
        else:
            raise ValueError("Invalid number of field names")

    if scale is True:
        for point in graph:
            for field in field_names:
                point[field] *= hist.scale

    return graph

def point_type(name, fields, srid_map):
    """
    Dynamically create a Point subclass.
    """
    class Point(type):
        def __new__(cls, name, bases, attrs):
            attrs['srid'] = srid_map.get(name, 4326)
            attrs['fields'] = fields
            return super().__new__(cls, name, bases, attrs)

    return type(name, (object,), {
        '__slots__': fields,
        '__metaclass__': Point
    })

def deprecated(message):
    def decorator(func):
        def wrapper(*args, **kwargs):
            print(f"Warning: {message}")
            return func(*args, **kwargs)
        return wrapper
    return decorator
